import{_ as e,n as a,p as o,Y as t}from"./chunks/framework.KP8KjELV.js";const V=JSON.parse('{"title":"VUE.CONF 第五届 Vue.js 开发者大会记录","description":"","frontmatter":{},"headers":[],"relativePath":"Blog/2022/5.2022vue开发者大会.md","filePath":"Blog/2022/5.2022vue开发者大会.md","lastUpdated":1703840066000}'),u={name:"Blog/2022/5.2022vue开发者大会.md"},l=t('<h1 id="vue-conf-第五届-vue-js-开发者大会记录" tabindex="-1">VUE.CONF 第五届 Vue.js 开发者大会记录 <a class="header-anchor" href="#vue-conf-第五届-vue-js-开发者大会记录" aria-label="Permalink to &quot;VUE.CONF 第五届 Vue.js 开发者大会记录&quot;">​</a></h1><blockquote><p>官网：<a href="https://vue.w3ctech.com/5" target="_blank" rel="noreferrer">https://vue.w3ctech.com/5</a> 第五届 Vue.js 开发者大会由 Vue.js 官方举办，将于 2022 年 12 月 10 日正式开启。本次大会将通过「前端圈」微信视频号和 B 站在线直播！</p></blockquote><h2 id="vue-的进化历程" tabindex="-1">Vue 的进化历程 <a class="header-anchor" href="#vue-的进化历程" aria-label="Permalink to &quot;Vue 的进化历程&quot;">​</a></h2><blockquote><p>演讲者：尤雨溪</p></blockquote><h2 id="使用-vue-构建-cli-应用" tabindex="-1">使用 Vue 构建 CLI 应用 <a class="header-anchor" href="#使用-vue-构建-cli-应用" aria-label="Permalink to &quot;使用 Vue 构建 CLI 应用&quot;">​</a></h2><blockquote><p>演讲者：蔡少辉 (webfansplz) 我们通常使用 Vue 来构建 Web 应用，但它的舞台其实不仅仅局限于浏览器。本次我将分享把 Vue 渲染到命令行界面上的相关实践。</p></blockquote><h2 id="vue-项目配置-最佳实践与个人偏见" tabindex="-1">Vue 项目配置：最佳实践与个人偏见 <a class="header-anchor" href="#vue-项目配置-最佳实践与个人偏见" aria-label="Permalink to &quot;Vue 项目配置：最佳实践与个人偏见&quot;">​</a></h2><blockquote><p>演讲者：蒋豪群</p></blockquote><h2 id="大型活动中的-vue-的静态检查实践" tabindex="-1">大型活动中的 Vue 的静态检查实践 <a class="header-anchor" href="#大型活动中的-vue-的静态检查实践" aria-label="Permalink to &quot;大型活动中的 Vue 的静态检查实践&quot;">​</a></h2><blockquote><p>演讲者：某兔 在 2022 春节前夕，快手的用户增长团队负责支撑了快手的春节和冬奥活动。我们会围绕着此次活动项目，介绍大型活动特点，策略，问题，以及静态的检查（类型检查， linter）是如何解决其中的工程问题的，以及我们在其中取得了什么样的收益。</p></blockquote><h2 id="vue-macros-介绍及基本原理" tabindex="-1">Vue Macros 介绍及基本原理 <a class="header-anchor" href="#vue-macros-介绍及基本原理" aria-label="Permalink to &quot;Vue Macros 介绍及基本原理&quot;">​</a></h2><blockquote><p>演讲者：三咲智子 Vue Macros 是一个扩充 Vue 宏和语法糖的库，本次分享主要让大家了解 Vue Macros 是什么，以及它的基本原理。</p></blockquote><h2 id="vue-3-0-ssr-在-bilibili-国际版实践" tabindex="-1">Vue 3.0 SSR 在 Bilibili 国际版实践 <a class="header-anchor" href="#vue-3-0-ssr-在-bilibili-国际版实践" aria-label="Permalink to &quot;Vue 3.0 SSR 在 Bilibili 国际版实践&quot;">​</a></h2><blockquote><p>演讲者：敖天羽 讲讲关于我们是怎么做 SSR 的故事：结合 Vue 我们做了哪些扩展，一个 SSR 系统如何设计与权衡。</p></blockquote><h2 id="vue-vite-中文文档翻译心得" tabindex="-1">Vue / Vite 中文文档翻译心得 <a class="header-anchor" href="#vue-vite-中文文档翻译心得" aria-label="Permalink to &quot;Vue / Vite 中文文档翻译心得&quot;">​</a></h2><blockquote><p>演讲者：唐梦予（ShenQingchuan） 本次分享将给大家从以下几个方面进行展开：</p><ul><li>如何更好地将技术内容译为中文</li><li>如何更好地管理开源社区下的翻译协作</li><li>对待翻译开源工作的理想与热情</li></ul></blockquote><h2 id="vue-之于-native-平台的三次进化" tabindex="-1">Vue 之于 Native 平台的三次进化 <a class="header-anchor" href="#vue-之于-native-平台的三次进化" aria-label="Permalink to &quot;Vue 之于 Native 平台的三次进化&quot;">​</a></h2><blockquote><p>演讲者：崔红保 基于 Vue 如何开发出媲美原生的移动 App？uni-app 团队做了三次大的重构探索；从最初的 WebView 渲染，到 WebView &amp; Weex 双渲染引擎，是前两个阶段的实现；今年，uni-app 团队进行了更有开创性的探索，尝试将 Vue + TS 代码，转译成 Kotlin/Swift，从而实现纯正的原生 App。本次分享，我将回顾介绍三次升级方案，及每次方案中，Vue 之于 Native 平台，我们做了哪些平台适配及优化，并会重点分享如何将 Vue 代码编译运行到 Kotlin/Swift 环境中。</p></blockquote><h2 id="vueuse-最佳实践" tabindex="-1">VueUse 最佳实践 <a class="header-anchor" href="#vueuse-最佳实践" aria-label="Permalink to &quot;VueUse 最佳实践&quot;">​</a></h2><blockquote><p>演讲者：Anthony Fu 我们在维护 VueUse 两年以来所积累的 Vue 组合式 API 的模式与最佳实践。</p></blockquote>',20),i=[l];function r(c,s,n,h,b,d){return a(),o("div",null,i)}const q=e(u,[["render",r]]);export{V as __pageData,q as default};
